const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let idx=0;
const T=Number(input[idx++]);
let outputs=[];
for(let t=0;t<T;++t){
  const N=Number(input[idx++]);
  const arr=[];
  for(let i=0;i<N;++i) arr.push(input[idx++]);
  outputs.push(arr.reverse().join(' '));
}
console.log(outputs.join('\n'));

